type IndexedAttestation* = object
  attestingIndices*: seq[uint64]
  data*: AttestationData
  signature*: Bytes96

proc sszBytesLen*(t: IndexedAttestation): int =
  result = 228
  result += len(t.attestingIndices) * 8

proc marshalSSZTo*(t: IndexedAttestation, buf: var seq[byte]) =
  let dstStart = len(buf)

  # Offset for 'attesting_indices'
  let offsetPos0 = len(buf)
  buf.add([byte 0, 0, 0, 0])
  # Field 'data'
  marshalSSZTo(t.data, buf)
  # Field 'signature'
  marshalSSZTo(t.signature, buf)

  # Dynamic field 'attesting_indices'
  block:
    let offset = uint32(len(buf) - dstStart)
    var tmp: array[4, byte]
    littleEndian32(addr tmp[0], unsafeAddr offset)
    copyMem(addr buf[offsetPos0], addr tmp[0], 4)
  for v in t.attestingIndices:
    block:
      var tmp: array[8, byte]
      var vv = v
      littleEndian64(addr tmp[0], addr vv)
      buf.add(tmp)

proc marshalSSZ*(t: IndexedAttestation): seq[byte] =
  result = newSeqOfCap[byte](sszBytesLen(t))
  marshalSSZTo(t, result)

proc fromSSZBytes*(T: typedesc[IndexedAttestation], data: openArray[byte]): IndexedAttestation =
  if len(data) < 228:
    raise newException(SszError, "buffer too small")
  var offset0: uint32
  littleEndian32(addr offset0, unsafeAddr data[0])
  let off0 = int(offset0)
  if off0 != 228:
    raise newException(SszError, "invalid offset")
  result.data = fromSSZBytes(AttestationData, data.toOpenArray(4, 132 - 1))
  result.signature = fromSSZBytes(Bytes96, data.toOpenArray(132, 228 - 1))

  block:
    let dynData = @(data.toOpenArray(off0, len(data) - 1))
    let count = len(dynData) div 8
    result.attestingIndices = newSeq[uint64](count)
    for i in 0 ..< count:
      let off = i * 8
      littleEndian64(addr result.attestingIndices[i], unsafeAddr dynData[off])

proc hashTreeRootWith*(t: IndexedAttestation, h: var Hasher) =
  let idx = h.index()

  # Field 'attesting_indices'
  block:
    let subIdx = h.index()
    for v in t.attestingIndices:
      h.appendUint64(v)
    h.fillUpTo32()
    h.merkleizeWithMixin(subIdx, uint64(len(t.attestingIndices)), 512'u64)

  # Field 'data'
  hashTreeRootWith(t.data, h)

  # Field 'signature'
  hashTreeRootWith(t.signature, h)

  h.merkleize(idx)

proc hashTreeRoot*(t: IndexedAttestation): array[32, byte] =
  var h = HasherPool.get()
  defer: HasherPool.put(h)
  hashTreeRootWith(t, h)
  result = h.hashRoot()

type AttesterSlashing* = object
  attestation1*: IndexedAttestation
  attestation2*: IndexedAttestation

proc sszBytesLen*(t: AttesterSlashing): int =
  result = 8
  result += sszBytesLen(t.attestation1)
  result += sszBytesLen(t.attestation2)

proc marshalSSZTo*(t: AttesterSlashing, buf: var seq[byte]) =
  let dstStart = len(buf)

  # Offset for 'attestation_1'
  let offsetPos0 = len(buf)
  buf.add([byte 0, 0, 0, 0])
  # Offset for 'attestation_2'
  let offsetPos1 = len(buf)
  buf.add([byte 0, 0, 0, 0])

  # Dynamic field 'attestation_1'
  block:
    let offset = uint32(len(buf) - dstStart)
    var tmp: array[4, byte]
    littleEndian32(addr tmp[0], unsafeAddr offset)
    copyMem(addr buf[offsetPos0], addr tmp[0], 4)
  marshalSSZTo(t.attestation1, buf)
  # Dynamic field 'attestation_2'
  block:
    let offset = uint32(len(buf) - dstStart)
    var tmp: array[4, byte]
    littleEndian32(addr tmp[0], unsafeAddr offset)
    copyMem(addr buf[offsetPos1], addr tmp[0], 4)
  marshalSSZTo(t.attestation2, buf)

proc marshalSSZ*(t: AttesterSlashing): seq[byte] =
  result = newSeqOfCap[byte](sszBytesLen(t))
  marshalSSZTo(t, result)

proc fromSSZBytes*(T: typedesc[AttesterSlashing], data: openArray[byte]): AttesterSlashing =
  if len(data) < 8:
    raise newException(SszError, "buffer too small")
  var offset0: uint32
  littleEndian32(addr offset0, unsafeAddr data[0])
  let off0 = int(offset0)
  if off0 != 8:
    raise newException(SszError, "invalid offset")
  var offset1: uint32
  littleEndian32(addr offset1, unsafeAddr data[4])
  let off1 = int(offset1)
  if off1 < off0 or off1 > len(data):
    raise newException(SszError, "invalid offset")

  block:
    result.attestation1 = fromSSZBytes(IndexedAttestation, data.toOpenArray(off0, off1 - 1))
  block:
    result.attestation2 = fromSSZBytes(IndexedAttestation, data.toOpenArray(off1, len(data) - 1))

proc hashTreeRootWith*(t: AttesterSlashing, h: var Hasher) =
  let idx = h.index()

  # Field 'attestation_1'
  hashTreeRootWith(t.attestation1, h)

  # Field 'attestation_2'
  hashTreeRootWith(t.attestation2, h)

  h.merkleize(idx)

proc hashTreeRoot*(t: AttesterSlashing): array[32, byte] =
  var h = HasherPool.get()
  defer: HasherPool.put(h)
  hashTreeRootWith(t, h)
  result = h.hashRoot()

