  aggregationBits*: seq[byte]
  data*: AttestationData
  signature*: Bytes96

proc sszBytesLen*(t: Attestation): int =
  result = 228
  result += len(t.aggregationBits)

proc marshalSSZTo*(t: Attestation, buf: var seq[byte]) =
  let dstStart = len(buf)

  # Offset for 'aggregation_bits'
  let offsetPos0 = len(buf)
  buf.add([byte 0, 0, 0, 0])
  # Field 'data'
  marshalSSZTo(t.data, buf)
  # Field 'signature'
  marshalSSZTo(t.signature, buf)

  # Dynamic field 'aggregation_bits'
  block:
    let offset = uint32(len(buf) - dstStart)
    var tmp: array[4, byte]
    littleEndian32(addr tmp[0], unsafeAddr offset)
    copyMem(addr buf[offsetPos0], addr tmp[0], 4)
  buf.add(t.aggregationBits)

proc marshalSSZ*(t: Attestation): seq[byte] =
  result = newSeqOfCap[byte](sszBytesLen(t))
  marshalSSZTo(t, result)

proc fromSSZBytes*(T: typedesc[Attestation], data: openArray[byte]): Attestation =
  if len(data) < 228:
    raise newException(SszError, "buffer too small")
  var offset0: uint32
  littleEndian32(addr offset0, unsafeAddr data[0])
  let off0 = int(offset0)
  if off0 != 228:
    raise newException(SszError, "invalid offset")
  result.data = fromSSZBytes(AttestationData, data.toOpenArray(4, 132 - 1))
  result.signature = fromSSZBytes(Bytes96, data.toOpenArray(132, 228 - 1))

  block:
    let dynData = @(data.toOpenArray(off0, len(data) - 1))
    result.aggregationBits = @(dynData)

proc hashTreeRootWith*(t: Attestation, h: var Hasher) =
  let idx = h.index()

  # Field 'aggregation_bits'
  h.putBitlist(t.aggregationBits, 2048'u64)

  # Field 'data'
  hashTreeRootWith(t.data, h)

  # Field 'signature'
  hashTreeRootWith(t.signature, h)

  h.merkleize(idx)

proc hashTreeRoot*(t: Attestation): array[32, byte] =
  var h = HasherPool.get()
  defer: HasherPool.put(h)
  hashTreeRootWith(t, h)
  result = h.hashRoot()

type ExecutionPayload* = object
  parentHash*: Bytes32
  feeRecipient*: Bytes20
  stateRoot*: Bytes32
  receiptsRoot*: Bytes32
  logsBloom*: Bytes256
  prevRandao*: Bytes32
  blockNumber*: uint64
  gasLimit*: uint64
  gasUsed*: uint64
  timestamp*: uint64
  extraData*: seq[byte]
  baseFeePerGas*: Bytes32
  blockHash*: Bytes32
  transactions*: seq[seq[byte]]
  withdrawals*: seq[Withdrawal]
  blobGasUsed*: uint64
  excessBlobGas*: uint64

proc sszBytesLen*(t: ExecutionPayload): int =
  result = 528
  result += len(t.extraData) * 1
  result += len(t.transactions) * 4
  for item in t.transactions:
    result += len(item)
  result += len(t.withdrawals) * 44

proc marshalSSZTo*(t: ExecutionPayload, buf: var seq[byte]) =
  let dstStart = len(buf)

  # Field 'parent_hash'
  marshalSSZTo(t.parentHash, buf)
  # Field 'fee_recipient'
  marshalSSZTo(t.feeRecipient, buf)
  # Field 'state_root'
  marshalSSZTo(t.stateRoot, buf)
  # Field 'receipts_root'
  marshalSSZTo(t.receiptsRoot, buf)
  # Field 'logs_bloom'
  marshalSSZTo(t.logsBloom, buf)
  # Field 'prev_randao'
  marshalSSZTo(t.prevRandao, buf)
  # Field 'block_number'
  block:
    var tmp: array[8, byte]
    var v = t.blockNumber
    littleEndian64(addr tmp[0], addr v)
    buf.add(tmp)
  # Field 'gas_limit'
  block:
    var tmp: array[8, byte]
    var v = t.gasLimit
    littleEndian64(addr tmp[0], addr v)
    buf.add(tmp)
  # Field 'gas_used'
  block:
    var tmp: array[8, byte]
    var v = t.gasUsed
    littleEndian64(addr tmp[0], addr v)
    buf.add(tmp)
  # Field 'timestamp'
  block:
    var tmp: array[8, byte]
    var v = t.timestamp
    littleEndian64(addr tmp[0], addr v)
    buf.add(tmp)
  # Offset for 'extra_data'
  let offsetPos0 = len(buf)
  buf.add([byte 0, 0, 0, 0])
  # Field 'base_fee_per_gas'
  marshalSSZTo(t.baseFeePerGas, buf)
  # Field 'block_hash'
  marshalSSZTo(t.blockHash, buf)
  # Offset for 'transactions'
  let offsetPos1 = len(buf)
  buf.add([byte 0, 0, 0, 0])
  # Offset for 'withdrawals'
  let offsetPos2 = len(buf)
  buf.add([byte 0, 0, 0, 0])
  # Field 'blob_gas_used'
  block:
    var tmp: array[8, byte]
    var v = t.blobGasUsed
    littleEndian64(addr tmp[0], addr v)
    buf.add(tmp)
  # Field 'excess_blob_gas'
  block:
    var tmp: array[8, byte]
    var v = t.excessBlobGas
    littleEndian64(addr tmp[0], addr v)
    buf.add(tmp)

  # Dynamic field 'extra_data'
  block:
    let offset = uint32(len(buf) - dstStart)
    var tmp: array[4, byte]
    littleEndian32(addr tmp[0], unsafeAddr offset)
    copyMem(addr buf[offsetPos0], addr tmp[0], 4)
  buf.add(t.extraData)
  # Dynamic field 'transactions'
  block:
    let offset = uint32(len(buf) - dstStart)
    var tmp: array[4, byte]
    littleEndian32(addr tmp[0], unsafeAddr offset)
    copyMem(addr buf[offsetPos1], addr tmp[0], 4)
  block:
    let listStart = len(buf)
    for i in 0 ..< len(t.transactions):
      buf.add([byte 0, 0, 0, 0])
    for i in 0 ..< len(t.transactions):
      block:
        let offset = uint32(len(buf) - listStart)
        var tmp: array[4, byte]
        littleEndian32(addr tmp[0], unsafeAddr offset)
        copyMem(addr buf[listStart + i * 4], addr tmp[0], 4)
      buf.add(t.transactions[i])
  # Dynamic field 'withdrawals'
  block:
    let offset = uint32(len(buf) - dstStart)
    var tmp: array[4, byte]
    littleEndian32(addr tmp[0], unsafeAddr offset)
    copyMem(addr buf[offsetPos2], addr tmp[0], 4)
  for item in t.withdrawals:
    marshalSSZTo(item, buf)

proc marshalSSZ*(t: ExecutionPayload): seq[byte] =
  result = newSeqOfCap[byte](sszBytesLen(t))
  marshalSSZTo(t, result)

proc fromSSZBytes*(T: typedesc[ExecutionPayload], data: openArray[byte]): ExecutionPayload =
  if len(data) < 528:
    raise newException(SszError, "buffer too small")
  result.parentHash = fromSSZBytes(Bytes32, data.toOpenArray(0, 32 - 1))
  result.feeRecipient = fromSSZBytes(Bytes20, data.toOpenArray(32, 52 - 1))
  result.stateRoot = fromSSZBytes(Bytes32, data.toOpenArray(52, 84 - 1))
  result.receiptsRoot = fromSSZBytes(Bytes32, data.toOpenArray(84, 116 - 1))
  result.logsBloom = fromSSZBytes(Bytes256, data.toOpenArray(116, 372 - 1))
  result.prevRandao = fromSSZBytes(Bytes32, data.toOpenArray(372, 404 - 1))
  littleEndian64(addr result.blockNumber, unsafeAddr data[404])
  littleEndian64(addr result.gasLimit, unsafeAddr data[412])
  littleEndian64(addr result.gasUsed, unsafeAddr data[420])
  littleEndian64(addr result.timestamp, unsafeAddr data[428])
  var offset0: uint32
  littleEndian32(addr offset0, unsafeAddr data[436])
  let off0 = int(offset0)
  if off0 != 528:
    raise newException(SszError, "invalid offset")
  result.baseFeePerGas = fromSSZBytes(Bytes32, data.toOpenArray(440, 472 - 1))
  result.blockHash = fromSSZBytes(Bytes32, data.toOpenArray(472, 504 - 1))
  var offset1: uint32
  littleEndian32(addr offset1, unsafeAddr data[504])
  let off1 = int(offset1)
  if off1 < off0 or off1 > len(data):
    raise newException(SszError, "invalid offset")
  var offset2: uint32
  littleEndian32(addr offset2, unsafeAddr data[508])
  let off2 = int(offset2)
  if off2 < off1 or off2 > len(data):
    raise newException(SszError, "invalid offset")
  littleEndian64(addr result.blobGasUsed, unsafeAddr data[512])
  littleEndian64(addr result.excessBlobGas, unsafeAddr data[520])

  block:
    let dynData = @(data.toOpenArray(off0, off1 - 1))
    result.extraData = @(dynData)
  block:
    let dynData = @(data.toOpenArray(off1, off2 - 1))
    if len(dynData) > 0:
      var firstOff: uint32
      littleEndian32(addr firstOff, unsafeAddr dynData[0])
      if int(firstOff) mod 4 != 0:
        raise newException(SszError, "invalid offset")
      let count = int(firstOff) div 4
      result.transactions = newSeq[seq[byte]](count)
      for i in 0 ..< count:
        var startOff: uint32
        littleEndian32(addr startOff, unsafeAddr dynData[i * 4])
        var endOff: int
        if i + 1 < count:
          var nextOff: uint32
          littleEndian32(addr nextOff, unsafeAddr dynData[(i + 1) * 4])
          endOff = int(nextOff)
        else:
          endOff = len(dynData)
        if int(startOff) > endOff or endOff > len(dynData):
          raise newException(SszError, "invalid offset")
        result.transactions[i] = @(dynData.toOpenArray(int(startOff), endOff - 1))
  block:
    let dynData = @(data.toOpenArray(off2, len(data) - 1))
    let count = len(dynData) div 44
    result.withdrawals = newSeq[Withdrawal](count)
    for i in 0 ..< count:
      let off = i * 44
      result.withdrawals[i] = fromSSZBytes(Withdrawal, dynData.toOpenArray(off, off + 44 - 1))

proc hashTreeRootWith*(t: ExecutionPayload, h: var Hasher) =
  let idx = h.index()

  # Field 'parent_hash'
  hashTreeRootWith(t.parentHash, h)

  # Field 'fee_recipient'
  hashTreeRootWith(t.feeRecipient, h)

  # Field 'state_root'
  hashTreeRootWith(t.stateRoot, h)

  # Field 'receipts_root'
  hashTreeRootWith(t.receiptsRoot, h)

  # Field 'logs_bloom'
  hashTreeRootWith(t.logsBloom, h)

  # Field 'prev_randao'
  hashTreeRootWith(t.prevRandao, h)

  # Field 'block_number'
  h.putUint64(t.blockNumber)

  # Field 'gas_limit'
  h.putUint64(t.gasLimit)

  # Field 'gas_used'
  h.putUint64(t.gasUsed)

  # Field 'timestamp'
  h.putUint64(t.timestamp)

  # Field 'extra_data'
  block:
    let subIdx = h.index()
    h.appendBytes32(t.extraData)
    h.merkleizeWithMixin(subIdx, uint64(len(t.extraData)), 1'u64)

  # Field 'base_fee_per_gas'
  hashTreeRootWith(t.baseFeePerGas, h)

  # Field 'block_hash'
  hashTreeRootWith(t.blockHash, h)

  # Field 'transactions'
  block:
    let subIdx = h.index()
    for item in t.transactions:
      let inner = h.index()
      h.appendBytes32(item)
      h.merkleizeWithMixin(inner, uint64(len(item)), 33554432'u64)
    h.merkleizeWithMixin(subIdx, uint64(len(t.transactions)), 1048576'u64)

  # Field 'withdrawals'
  block:
    let subIdx = h.index()
    for item in t.withdrawals:
      hashTreeRootWith(item, h)
    h.merkleizeWithMixin(subIdx, uint64(len(t.withdrawals)), 16'u64)

  # Field 'blob_gas_used'
  h.putUint64(t.blobGasUsed)

  # Field 'excess_blob_gas'
  h.putUint64(t.excessBlobGas)

  h.merkleize(idx)

proc hashTreeRoot*(t: ExecutionPayload): array[32, byte] =
  var h = HasherPool.get()
  defer: HasherPool.put(h)
  hashTreeRootWith(t, h)
  result = h.hashRoot()

type BeaconBlockBody* = object
  randaoReveal*: Bytes96
  eth1Data*: ETH1Data
  graffiti*: Bytes32
  proposerSlashings*: seq[ProposerSlashing]
  attesterSlashings*: seq[AttesterSlashing]
  attestations*: seq[Attestation]
  deposits*: seq[Deposit]
  voluntaryExits*: seq[SignedVoluntaryExit]
  syncAggregate*: SyncAggregate
  executionPayload*: ExecutionPayload
  blsToExecutionChanges*: seq[SignedBLSToExecutionChange]
  blobKzgCommitments*: seq[KZGCommitment]

proc sszBytesLen*(t: BeaconBlockBody): int =
  result = 392
  result += len(t.proposerSlashings) * 416
  result += len(t.attesterSlashings) * 4
  for item in t.attesterSlashings:
    result += sszBytesLen(item)
  result += len(t.attestations) * 4
  for item in t.attestations:
    result += sszBytesLen(item)
  result += len(t.deposits) * 1240
  result += len(t.voluntaryExits) * 112
  result += sszBytesLen(t.executionPayload)
  result += len(t.blsToExecutionChanges) * 172
  result += len(t.blobKzgCommitments) * 48

proc marshalSSZTo*(t: BeaconBlockBody, buf: var seq[byte]) =
  let dstStart = len(buf)

  # Field 'randao_reveal'
  marshalSSZTo(t.randaoReveal, buf)
  # Field 'eth1_data'
  marshalSSZTo(t.eth1Data, buf)
  # Field 'graffiti'
  marshalSSZTo(t.graffiti, buf)
  # Offset for 'proposer_slashings'
  let offsetPos0 = len(buf)
  buf.add([byte 0, 0, 0, 0])
  # Offset for 'attester_slashings'
  let offsetPos1 = len(buf)
  buf.add([byte 0, 0, 0, 0])
  # Offset for 'attestations'
  let offsetPos2 = len(buf)
  buf.add([byte 0, 0, 0, 0])
  # Offset for 'deposits'
  let offsetPos3 = len(buf)
  buf.add([byte 0, 0, 0, 0])
  # Offset for 'voluntary_exits'
  let offsetPos4 = len(buf)
  buf.add([byte 0, 0, 0, 0])
  # Field 'sync_aggregate'
  marshalSSZTo(t.syncAggregate, buf)
  # Offset for 'execution_payload'
  let offsetPos5 = len(buf)
  buf.add([byte 0, 0, 0, 0])
  # Offset for 'bls_to_execution_changes'
  let offsetPos6 = len(buf)
  buf.add([byte 0, 0, 0, 0])
  # Offset for 'blob_kzg_commitments'
  let offsetPos7 = len(buf)
  buf.add([byte 0, 0, 0, 0])

  # Dynamic field 'proposer_slashings'
  block:
    let offset = uint32(len(buf) - dstStart)
    var tmp: array[4, byte]
    littleEndian32(addr tmp[0], unsafeAddr offset)
    copyMem(addr buf[offsetPos0], addr tmp[0], 4)
  for item in t.proposerSlashings:
    marshalSSZTo(item, buf)
  # Dynamic field 'attester_slashings'
  block:
    let offset = uint32(len(buf) - dstStart)
    var tmp: array[4, byte]
    littleEndian32(addr tmp[0], unsafeAddr offset)
    copyMem(addr buf[offsetPos1], addr tmp[0], 4)
  block:
    let listStart = len(buf)
    for i in 0 ..< len(t.attesterSlashings):
      buf.add([byte 0, 0, 0, 0])
    for i in 0 ..< len(t.attesterSlashings):
      block:
        let offset = uint32(len(buf) - listStart)
        var tmp: array[4, byte]
        littleEndian32(addr tmp[0], unsafeAddr offset)
        copyMem(addr buf[listStart + i * 4], addr tmp[0], 4)
      marshalSSZTo(t.attesterSlashings[i], buf)
  # Dynamic field 'attestations'
  block:
    let offset = uint32(len(buf) - dstStart)
    var tmp: array[4, byte]
    littleEndian32(addr tmp[0], unsafeAddr offset)
    copyMem(addr buf[offsetPos2], addr tmp[0], 4)
  block:
    let listStart = len(buf)
    for i in 0 ..< len(t.attestations):
      buf.add([byte 0, 0, 0, 0])
    for i in 0 ..< len(t.attestations):
      block:
        let offset = uint32(len(buf) - listStart)
        var tmp: array[4, byte]
        littleEndian32(addr tmp[0], unsafeAddr offset)
        copyMem(addr buf[listStart + i * 4], addr tmp[0], 4)
      marshalSSZTo(t.attestations[i], buf)
  # Dynamic field 'deposits'
  block:
    let offset = uint32(len(buf) - dstStart)
    var tmp: array[4, byte]
    littleEndian32(addr tmp[0], unsafeAddr offset)
    copyMem(addr buf[offsetPos3], addr tmp[0], 4)
  for item in t.deposits:
    marshalSSZTo(item, buf)
  # Dynamic field 'voluntary_exits'
  block:
    let offset = uint32(len(buf) - dstStart)
    var tmp: array[4, byte]
    littleEndian32(addr tmp[0], unsafeAddr offset)
    copyMem(addr buf[offsetPos4], addr tmp[0], 4)
  for item in t.voluntaryExits:
    marshalSSZTo(item, buf)
  # Dynamic field 'execution_payload'
  block:
    let offset = uint32(len(buf) - dstStart)
    var tmp: array[4, byte]
    littleEndian32(addr tmp[0], unsafeAddr offset)
    copyMem(addr buf[offsetPos5], addr tmp[0], 4)
  marshalSSZTo(t.executionPayload, buf)
  # Dynamic field 'bls_to_execution_changes'
  block:
    let offset = uint32(len(buf) - dstStart)
    var tmp: array[4, byte]
    littleEndian32(addr tmp[0], unsafeAddr offset)
    copyMem(addr buf[offsetPos6], addr tmp[0], 4)
  for item in t.blsToExecutionChanges:
    marshalSSZTo(item, buf)
  # Dynamic field 'blob_kzg_commitments'
  block:
    let offset = uint32(len(buf) - dstStart)
    var tmp: array[4, byte]
    littleEndian32(addr tmp[0], unsafeAddr offset)
    copyMem(addr buf[offsetPos7], addr tmp[0], 4)
  for item in t.blobKzgCommitments:
    marshalSSZTo(item, buf)

proc marshalSSZ*(t: BeaconBlockBody): seq[byte] =
  result = newSeqOfCap[byte](sszBytesLen(t))
  marshalSSZTo(t, result)

proc fromSSZBytes*(T: typedesc[BeaconBlockBody], data: openArray[byte]): BeaconBlockBody =
  if len(data) < 392:
    raise newException(SszError, "buffer too small")
  result.randaoReveal = fromSSZBytes(Bytes96, data.toOpenArray(0, 96 - 1))
  result.eth1Data = fromSSZBytes(ETH1Data, data.toOpenArray(96, 168 - 1))
  result.graffiti = fromSSZBytes(Bytes32, data.toOpenArray(168, 200 - 1))
  var offset0: uint32
  littleEndian32(addr offset0, unsafeAddr data[200])
  let off0 = int(offset0)
  if off0 != 392:
    raise newException(SszError, "invalid offset")
  var offset1: uint32
  littleEndian32(addr offset1, unsafeAddr data[204])
  let off1 = int(offset1)
  if off1 < off0 or off1 > len(data):
    raise newException(SszError, "invalid offset")
  var offset2: uint32
  littleEndian32(addr offset2, unsafeAddr data[208])
  let off2 = int(offset2)
  if off2 < off1 or off2 > len(data):
    raise newException(SszError, "invalid offset")
  var offset3: uint32
  littleEndian32(addr offset3, unsafeAddr data[212])
  let off3 = int(offset3)
  if off3 < off2 or off3 > len(data):
    raise newException(SszError, "invalid offset")
  var offset4: uint32
  littleEndian32(addr offset4, unsafeAddr data[216])
  let off4 = int(offset4)
  if off4 < off3 or off4 > len(data):
    raise newException(SszError, "invalid offset")
  result.syncAggregate = fromSSZBytes(SyncAggregate, data.toOpenArray(220, 380 - 1))
  var offset5: uint32
  littleEndian32(addr offset5, unsafeAddr data[380])
  let off5 = int(offset5)
  if off5 < off4 or off5 > len(data):
    raise newException(SszError, "invalid offset")
  var offset6: uint32
  littleEndian32(addr offset6, unsafeAddr data[384])
  let off6 = int(offset6)
  if off6 < off5 or off6 > len(data):
    raise newException(SszError, "invalid offset")
  var offset7: uint32
  littleEndian32(addr offset7, unsafeAddr data[388])
  let off7 = int(offset7)
  if off7 < off6 or off7 > len(data):
    raise newException(SszError, "invalid offset")

  block:
    let dynData = @(data.toOpenArray(off0, off1 - 1))
    let count = len(dynData) div 416
    result.proposerSlashings = newSeq[ProposerSlashing](count)
    for i in 0 ..< count:
      let off = i * 416
      result.proposerSlashings[i] = fromSSZBytes(ProposerSlashing, dynData.toOpenArray(off, off + 416 - 1))
  block:
    let dynData = @(data.toOpenArray(off1, off2 - 1))
    if len(dynData) > 0:
      var firstOff: uint32
      littleEndian32(addr firstOff, unsafeAddr dynData[0])
      if int(firstOff) mod 4 != 0:
        raise newException(SszError, "invalid offset")
      let count = int(firstOff) div 4
      result.attesterSlashings = newSeq[AttesterSlashing](count)
      for i in 0 ..< count:
        var startOff: uint32
        littleEndian32(addr startOff, unsafeAddr dynData[i * 4])
        var endOff: int
        if i + 1 < count:
          var nextOff: uint32
          littleEndian32(addr nextOff, unsafeAddr dynData[(i + 1) * 4])
          endOff = int(nextOff)
        else:
          endOff = len(dynData)
        if int(startOff) > endOff or endOff > len(dynData):
          raise newException(SszError, "invalid offset")
        result.attesterSlashings[i] = fromSSZBytes(AttesterSlashing, dynData.toOpenArray(int(startOff), endOff - 1))
  block:
    let dynData = @(data.toOpenArray(off2, off3 - 1))
    if len(dynData) > 0:
      var firstOff: uint32
      littleEndian32(addr firstOff, unsafeAddr dynData[0])
      if int(firstOff) mod 4 != 0:
        raise newException(SszError, "invalid offset")
      let count = int(firstOff) div 4
      result.attestations = newSeq[Attestation](count)
      for i in 0 ..< count:
        var startOff: uint32
        littleEndian32(addr startOff, unsafeAddr dynData[i * 4])
        var endOff: int
        if i + 1 < count:
          var nextOff: uint32
          littleEndian32(addr nextOff, unsafeAddr dynData[(i + 1) * 4])
          endOff = int(nextOff)
        else:
          endOff = len(dynData)
        if int(startOff) > endOff or endOff > len(dynData):
          raise newException(SszError, "invalid offset")
        result.attestations[i] = fromSSZBytes(Attestation, dynData.toOpenArray(int(startOff), endOff - 1))
  block:
    let dynData = @(data.toOpenArray(off3, off4 - 1))
    let count = len(dynData) div 1240
    result.deposits = newSeq[Deposit](count)
    for i in 0 ..< count:
      let off = i * 1240
      result.deposits[i] = fromSSZBytes(Deposit, dynData.toOpenArray(off, off + 1240 - 1))
  block:
    let dynData = @(data.toOpenArray(off4, off5 - 1))
    let count = len(dynData) div 112
    result.voluntaryExits = newSeq[SignedVoluntaryExit](count)
    for i in 0 ..< count:
      let off = i * 112
      result.voluntaryExits[i] = fromSSZBytes(SignedVoluntaryExit, dynData.toOpenArray(off, off + 112 - 1))
  block:
    result.executionPayload = fromSSZBytes(ExecutionPayload, data.toOpenArray(off5, off6 - 1))
  block:
    let dynData = @(data.toOpenArray(off6, off7 - 1))
    let count = len(dynData) div 172
    result.blsToExecutionChanges = newSeq[SignedBLSToExecutionChange](count)
    for i in 0 ..< count:
      let off = i * 172
      result.blsToExecutionChanges[i] = fromSSZBytes(SignedBLSToExecutionChange, dynData.toOpenArray(off, off + 172 - 1))
  block:
    let dynData = @(data.toOpenArray(off7, len(data) - 1))
    let count = len(dynData) div 48
    result.blobKzgCommitments = newSeq[KZGCommitment](count)
    for i in 0 ..< count:
      let off = i * 48
      result.blobKzgCommitments[i] = fromSSZBytes(KZGCommitment, dynData.toOpenArray(off, off + 48 - 1))

proc hashTreeRootWith*(t: BeaconBlockBody, h: var Hasher) =
  let idx = h.index()

  # Field 'randao_reveal'
  hashTreeRootWith(t.randaoReveal, h)

  # Field 'eth1_data'
  hashTreeRootWith(t.eth1Data, h)

  # Field 'graffiti'
  hashTreeRootWith(t.graffiti, h)

  # Field 'proposer_slashings'
  block:
    let subIdx = h.index()
    for item in t.proposerSlashings:
      hashTreeRootWith(item, h)
    h.merkleizeWithMixin(subIdx, uint64(len(t.proposerSlashings)), 16'u64)

  # Field 'attester_slashings'
  block:
    let subIdx = h.index()
    for item in t.attesterSlashings:
      hashTreeRootWith(item, h)
    h.merkleizeWithMixin(subIdx, uint64(len(t.attesterSlashings)), 2'u64)

  # Field 'attestations'
  block:
    let subIdx = h.index()
    for item in t.attestations:
      hashTreeRootWith(item, h)
    h.merkleizeWithMixin(subIdx, uint64(len(t.attestations)), 128'u64)

  # Field 'deposits'
  block:
    let subIdx = h.index()
    for item in t.deposits:
      hashTreeRootWith(item, h)
    h.merkleizeWithMixin(subIdx, uint64(len(t.deposits)), 16'u64)

  # Field 'voluntary_exits'
  block:
    let subIdx = h.index()
    for item in t.voluntaryExits:
      hashTreeRootWith(item, h)
    h.merkleizeWithMixin(subIdx, uint64(len(t.voluntaryExits)), 16'u64)

  # Field 'sync_aggregate'
  hashTreeRootWith(t.syncAggregate, h)

  # Field 'execution_payload'
  hashTreeRootWith(t.executionPayload, h)

  # Field 'bls_to_execution_changes'
  block:
    let subIdx = h.index()
    for item in t.blsToExecutionChanges:
      hashTreeRootWith(item, h)
    h.merkleizeWithMixin(subIdx, uint64(len(t.blsToExecutionChanges)), 16'u64)

  # Field 'blob_kzg_commitments'
  block:
    let subIdx = h.index()
    for item in t.blobKzgCommitments:
      hashTreeRootWith(item, h)
    h.merkleizeWithMixin(subIdx, uint64(len(t.blobKzgCommitments)), 4096'u64)

  h.merkleize(idx)

proc hashTreeRoot*(t: BeaconBlockBody): array[32, byte] =
  var h = HasherPool.get()
  defer: HasherPool.put(h)
  hashTreeRootWith(t, h)
  result = h.hashRoot()

type BeaconBlock* = object
  slot*: uint64
  proposerIndex*: uint64
  parentRoot*: Bytes32
  stateRoot*: Bytes32
  body*: BeaconBlockBody

proc sszBytesLen*(t: BeaconBlock): int =
  result = 84
  result += sszBytesLen(t.body)

proc marshalSSZTo*(t: BeaconBlock, buf: var seq[byte]) =
  let dstStart = len(buf)

  # Field 'slot'
  block:
    var tmp: array[8, byte]
    var v = t.slot
    littleEndian64(addr tmp[0], addr v)
    buf.add(tmp)
  # Field 'proposer_index'
  block:
    var tmp: array[8, byte]
    var v = t.proposerIndex
    littleEndian64(addr tmp[0], addr v)
    buf.add(tmp)
  # Field 'parent_root'
  marshalSSZTo(t.parentRoot, buf)
  # Field 'state_root'
  marshalSSZTo(t.stateRoot, buf)
  # Offset for 'body'
  let offsetPos0 = len(buf)
  buf.add([byte 0, 0, 0, 0])

  # Dynamic field 'body'
  block:
    let offset = uint32(len(buf) - dstStart)
    var tmp: array[4, byte]
    littleEndian32(addr tmp[0], unsafeAddr offset)
    copyMem(addr buf[offsetPos0], addr tmp[0], 4)
  marshalSSZTo(t.body, buf)

proc marshalSSZ*(t: BeaconBlock): seq[byte] =
  result = newSeqOfCap[byte](sszBytesLen(t))
  marshalSSZTo(t, result)

proc fromSSZBytes*(T: typedesc[BeaconBlock], data: openArray[byte]): BeaconBlock =
  if len(data) < 84:
    raise newException(SszError, "buffer too small")
  littleEndian64(addr result.slot, unsafeAddr data[0])
  littleEndian64(addr result.proposerIndex, unsafeAddr data[8])
  result.parentRoot = fromSSZBytes(Bytes32, data.toOpenArray(16, 48 - 1))
  result.stateRoot = fromSSZBytes(Bytes32, data.toOpenArray(48, 80 - 1))
  var offset0: uint32
  littleEndian32(addr offset0, unsafeAddr data[80])
  let off0 = int(offset0)
  if off0 != 84:
    raise newException(SszError, "invalid offset")

  block:
    result.body = fromSSZBytes(BeaconBlockBody, data.toOpenArray(off0, len(data) - 1))

proc hashTreeRootWith*(t: BeaconBlock, h: var Hasher) =
  let idx = h.index()

  # Field 'slot'
  h.putUint64(t.slot)

  # Field 'proposer_index'
  h.putUint64(t.proposerIndex)

  # Field 'parent_root'
  hashTreeRootWith(t.parentRoot, h)

  # Field 'state_root'
  hashTreeRootWith(t.stateRoot, h)

  # Field 'body'
  hashTreeRootWith(t.body, h)

  h.merkleize(idx)

proc hashTreeRoot*(t: BeaconBlock): array[32, byte] =
  var h = HasherPool.get()
  defer: HasherPool.put(h)
  hashTreeRootWith(t, h)
  result = h.hashRoot()

type SignedBeaconBlock* = object
  message*: BeaconBlock
  signature*: Bytes96

proc sszBytesLen*(t: SignedBeaconBlock): int =
  result = 100
  result += sszBytesLen(t.message)

proc marshalSSZTo*(t: SignedBeaconBlock, buf: var seq[byte]) =
  let dstStart = len(buf)

  # Offset for 'message'
  let offsetPos0 = len(buf)
  buf.add([byte 0, 0, 0, 0])
  # Field 'signature'
  marshalSSZTo(t.signature, buf)

  # Dynamic field 'message'
  block:
    let offset = uint32(len(buf) - dstStart)
    var tmp: array[4, byte]
    littleEndian32(addr tmp[0], unsafeAddr offset)
    copyMem(addr buf[offsetPos0], addr tmp[0], 4)
  marshalSSZTo(t.message, buf)

proc marshalSSZ*(t: SignedBeaconBlock): seq[byte] =
  result = newSeqOfCap[byte](sszBytesLen(t))
  marshalSSZTo(t, result)

proc fromSSZBytes*(T: typedesc[SignedBeaconBlock], data: openArray[byte]): SignedBeaconBlock =
  if len(data) < 100:
    raise newException(SszError, "buffer too small")
  var offset0: uint32
  littleEndian32(addr offset0, unsafeAddr data[0])
  let off0 = int(offset0)
  if off0 != 100:
    raise newException(SszError, "invalid offset")
  result.signature = fromSSZBytes(Bytes96, data.toOpenArray(4, 100 - 1))

  block:
    result.message = fromSSZBytes(BeaconBlock, data.toOpenArray(off0, len(data) - 1))

proc hashTreeRootWith*(t: SignedBeaconBlock, h: var Hasher) =
  let idx = h.index()

  # Field 'message'
  hashTreeRootWith(t.message, h)

  # Field 'signature'
  hashTreeRootWith(t.signature, h)

  h.merkleize(idx)

proc hashTreeRoot*(t: SignedBeaconBlock): array[32, byte] =
  var h = HasherPool.get()
  defer: HasherPool.put(h)
  hashTreeRootWith(t, h)
  result = h.hashRoot()
